const mysqlMessages = []; // Array para almacenar los mensajes que se enviarán al nodo MySQL

// Función simple para convertir fecha de dd/mm/yyyy a yyyy-mm-dd
function convertirFecha(fechaStr) {
    if (!fechaStr) return '';

    const fecha = fechaStr.toString().trim();

    // Si ya está en formato yyyy-mm-dd, retornar tal cual
    if (/^\d{4}-\d{2}-\d{2}$/.test(fecha)) {
        return fecha;
    }

    // Convertir de dd/mm/yyyy a yyyy-mm-dd
    const partes = fecha.split('/');
    if (partes.length === 3) {
        const dia = partes[0].padStart(2, '0');
        const mes = partes[1].padStart(2, '0');
        const año = partes[2];
        return `${año}-${mes}-${dia}`;
    }

    return fecha; // Si no coincide, mantener original
}

