    INSERT INTO consumos_x_hora (fechaindustrial, hora, gas, kilos, humedad, bolsas)
    VALUES (?, ?, ?, ?, ?, ?)
    ON DUPLICATE KEY UPDATE 
        fechaindustrial = VALUES(fechaindustrial),
        hora = VALUES(hora),
        gas = VALUES(gas),
        kilos = VALUES(kilos),
        humedad = VALUES(humedad),
        bolsas = VALUES(bolsas)
`;

// Iterar sobre cada fila recibida de MSSQL
for (const row of mssqlRows) {
    // Convertir fecha de dd/mm/yyyy a yyyy-mm-dd
    const fechaindustrial = convertirFecha(row.fechaindustrial) || '';
    const hora = row.hora || '';
    const gas = row.gas || 0;
    const kilos = row.kilos || 0;
    const humedad = row.humedad || 0;
    const bolsas = row.bolsas || 0;

    // Crear el array de parámetros en el ORDEN CORRECTO para la consulta preparada
    const params = [fechaindustrial, hora, gas, kilos, humedad, bolsas];

    // Crear un nuevo mensaje para el nodo MySQL
    mysqlMessages.push({
        payload: params,
        topic: insertSql,
        // También puedes incluir la fila original para debugging
        _originalRow: row
    });
}

// Devolver los mensajes para el nodo MySQL
return [mysqlMessages];

